with open("./src/dds/wave-rom.hex", "wt") as f:
    for i, rc in enumerate(flat_hex):
        f.write(rc)
        if ((i + 1) % 4) == 0:
            f.write('\n')
        else:
            f.write(' ')

def hex_to_signed_32(hex_str):
    return ctypes.c_int32(int(hex_str, 16)).value

# Convert all samples
samples = [hex_to_signed_32(h) for h in flat_hex]

print(len(samples))

# Plotting the segment
plt.plot(range(len(samples)), samples, marker='o')
plt.grid(True)

plt.show()

# Print statistics for debugging
print(f"Total samples analyzed: {len(samples)}")
print(f"Max value: {max(samples)} (Hex: {hex(max(samples))})")
print(f"Min value: {min(samples)} (Hex: {hex(min(samples))})")
